"use client"

import { useState } from 'react'
import { ShoppingCart, Heart, Globe, Check } from 'lucide-react'
import { PlatformIcon } from './platform-icons'
import { useCart } from '@/lib/cart-context'
import { useCurrency } from '@/lib/currency-context'

const cn = (...classes: (string | boolean | undefined)[]) => classes.filter(Boolean).join(' ')

export function ProductCard({ game }: { game: any }) {
  const { addItem } = useCart()
  const { formatPrice } = useCurrency()
  
  const [isHovered, setIsHovered] = useState(false)
  const [isWishlisted, setIsWishlisted] = useState(false)
  const [isAdding, setIsAdding] = useState(false)
  const [imageError, setImageError] = useState(false)

  // --- DETECTOR DE VARIABLES (DJANGO VS FRONTEND) ---
  const titulo = game.titulo || game.title || "Sin título";
  const precioRaw = game.precio || game.price || 0;
  const portadaRaw = game.portada || game.image || game.image_url;
  const categoria = game.categoria_nombre || game.category || "General";
  const stockEtiqueta = game.etiqueta_stock || game.stockStatus || "Disponible";

  // Asegurar que el precio sea número
  const numericPrice = Number(precioRaw);

  // Asegurar que la URL de la imagen sea completa
  const getImageUrl = (url: string) => {
    if (!url) return `https://placehold.co/600x800/1a1a1f/7c3aed?text=No+Image`;
    if (url.startsWith('http')) return url;
    return `http://127.0.0.1:8000${url}`;
  };

  const finalImageUrl = getImageUrl(portadaRaw);

  const handleAddToCart = (e: React.MouseEvent) => {
    e.stopPropagation()
    setIsAdding(true)
    addItem({
      id: game.id,
      titulo: titulo,
      price: numericPrice,
      portada: finalImageUrl
    })
    setTimeout(() => setIsAdding(false), 800)
  }

  return (
    <div
      className={cn(
        "group relative rounded-xl overflow-hidden transition-all duration-300 bg-[#1a1a1f] border border-[#2d2d35]/50",
        isHovered && "transform -translate-y-1 shadow-2xl shadow-[#7c3aed]/20 border-[#7c3aed]/50"
      )}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className="relative aspect-[3/4] overflow-hidden">
        <img
          src={imageError ? `https://placehold.co/600x800/1a1a1f/7c3aed?text=${titulo}` : finalImageUrl}
          alt={titulo}
          onError={() => setImageError(true)}
          className={cn(
            "w-full h-full object-cover transition-transform duration-700",
            isHovered ? "scale-110" : "scale-100"
          )}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#101014] via-transparent to-transparent opacity-80" />

        <button
          onClick={(e) => {
            e.stopPropagation();
            setIsWishlisted(!isWishlisted);
          }}
          className={cn(
            "absolute top-3 right-3 p-2.5 rounded-full transition-all z-10 backdrop-blur-md",
            isWishlisted ? "bg-[#ef4444] text-white" : "bg-black/40 text-white hover:bg-black/60"
          )}
        >
          <Heart className={cn("w-4 h-4", isWishlisted && "fill-current")} />
        </button>

        <div className={cn(
          "absolute bottom-0 left-0 right-0 p-4 transform transition-all duration-300 z-20",
          isHovered ? "translate-y-0 opacity-100" : "translate-y-4 opacity-0"
        )}>
          <button
            onClick={handleAddToCart}
            className="w-full flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-sm bg-[#7c3aed] text-white"
          >
            {isAdding ? <Check className="w-5 h-5" /> : <ShoppingCart className="w-4 h-4" />}
            {isAdding ? '¡Añadido!' : 'Añadir al carrito'}
          </button>
        </div>
      </div>

      <div className="p-4">
        <div className="flex items-center justify-between mb-2">
          <span className="text-[10px] px-2 py-1 bg-[#7c3aed]/10 text-[#a78bfa] rounded-md uppercase font-bold">
            {categoria}
          </span>
          <span className="text-[10px] text-emerald-400 font-medium">
            {stockEtiqueta}
          </span>
        </div>
        <h3 className="font-bold text-white text-sm leading-snug mb-3 line-clamp-2">
          {titulo}
        </h3>
        <div className="flex items-center justify-between">
          <span className="text-lg font-black text-[#00e5ff]">
            {formatPrice(numericPrice)}
          </span>
          <div className="flex items-center gap-1 text-gray-500">
            <Globe className="w-3 h-3" />
            <span className="text-[10px] font-bold uppercase">Global</span>
          </div>
        </div>
      </div>
    </div>
  )
}