"use client"

import { useState } from 'react'
import { Search, Heart, ShoppingCart, Globe, Menu, X, ChevronDown, User, Sun, Moon } from 'lucide-react'

// Definimos los datos locales que antes venían de /lib
const regions = [
  { id: 'mx', name: 'México', flag: '🇲🇽', currency: 'MXN' },
  { id: 'us', name: 'Estados Unidos', flag: '🇺🇸', currency: 'USD' }
]

interface HeaderProps {
  onSearch: (query: string) => void
  searchQuery: string
  onLoginClick: () => void
}

export function Header({ onSearch, searchQuery, onLoginClick }: HeaderProps) {
  // Estados locales para sustituir los contextos faltantes
  const [theme, setTheme] = useState<'dark' | 'light'>('dark')
  const [region, setRegion] = useState('mx')
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false)
  const [isRegionOpen, setIsRegionOpen] = useState(false)
  
  // Valores simulados
  const totalItems = 0 
  const currency = region === 'mx' ? 'MXN' : 'USD'
  const currentRegion = regions.find(r => r.id === region)

  // Función local para sustituir cn()
  const cn = (...classes: (string | boolean | undefined)[]) => classes.filter(Boolean).join(' ')

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark')

  return (
    <header className={cn(
      "sticky top-0 z-50 border-b transition-colors",
      theme === 'dark' 
        ? "bg-[#101014] border-[#2d2d35]" 
        : "bg-white border-gray-200"
    )}>
      <div className="max-w-[1400px] mx-auto px-4">
        <div className="flex items-center justify-between h-16 gap-4">
          {/* Logo */}
          <div className="flex items-center gap-2 flex-shrink-0">
            <div className="text-2xl font-bold bg-gradient-to-r from-[#7c3aed] to-[#00e5ff] bg-clip-text text-transparent">
              RANDOMPLAY
            </div>
          </div>

          {/* Desktop Navigation */}
          <nav className="hidden lg:flex items-center gap-1">
            <a href="#" className={cn(
              "px-3 py-2 text-sm transition-colors rounded-lg",
              theme === 'dark' ? "text-[#9ca3af] hover:text-white hover:bg-[#1a1a1f]" : "text-gray-600 hover:text-gray-900 hover:bg-gray-100"
            )}>Juegos</a>
            <a href="#" className={cn(
              "px-3 py-2 text-sm transition-colors rounded-lg",
              theme === 'dark' ? "text-[#9ca3af] hover:text-white hover:bg-[#1a1a1f]" : "text-gray-600 hover:text-gray-900 hover:bg-gray-100"
            )}>DLC</a>
            <a href="#nuestra-historia" className="px-3 py-2 text-sm text-[#7c3aed] hover:text-[#9d6eff] transition-colors rounded-lg hover:bg-[#7c3aed]/10 font-medium">Nosotros</a>
          </nav>

          {/* Search Bar - Desktop */}
          <div className="hidden md:flex flex-1 max-w-xl">
            <div className="relative w-full">
              <Search className={cn("absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5", theme === 'dark' ? "text-[#9ca3af]" : "text-gray-400")} />
              <input
                type="text"
                placeholder="Buscar juegos..."
                value={searchQuery}
                onChange={(e) => onSearch(e.target.value)}
                className={cn(
                  "w-full pl-10 pr-4 py-2.5 border rounded-lg transition-all focus:outline-none focus:border-[#7c3aed]",
                  theme === 'dark' ? "bg-[#1a1a1f] border-[#2d2d35] text-white" : "bg-gray-50 border-gray-200 text-gray-900"
                )}
              />
            </div>
          </div>

          {/* Right Side Icons */}
          <div className="flex items-center gap-2">
            <button onClick={toggleTheme} className={cn("p-2.5 rounded-lg", theme === 'dark' ? "text-[#9ca3af] hover:text-white hover:bg-[#1a1a1f]" : "text-gray-500 hover:text-gray-900 hover:bg-gray-100")}>
              {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            {/* Region Selector */}
            <div className="relative hidden sm:block">
              <button onClick={() => setIsRegionOpen(!isRegionOpen)} className={cn("flex items-center gap-1.5 px-3 py-2 text-sm rounded-lg", theme === 'dark' ? "text-[#9ca3af] hover:text-white hover:bg-[#1a1a1f]" : "text-gray-500 hover:text-gray-900 hover:bg-gray-100")}>
                <span className="text-lg">{currentRegion?.flag}</span>
                <span>{currency}</span>
                <ChevronDown className={cn("w-4 h-4 transition-transform", isRegionOpen && "rotate-180")} />
              </button>
              
              {isRegionOpen && (
                <div className={cn("absolute top-full right-0 mt-2 w-48 border rounded-lg shadow-xl", theme === 'dark' ? "bg-[#1a1a1f] border-[#2d2d35]" : "bg-white border-gray-200")}>
                  {regions.map((r) => (
                    <button key={r.id} onClick={() => { setRegion(r.id); setIsRegionOpen(false); }} className={cn("w-full px-4 py-2.5 text-left text-sm flex items-center gap-3", theme === 'dark' ? "hover:bg-[#252529] text-white" : "hover:bg-gray-50 text-gray-900")}>
                      <span>{r.flag}</span> <span>{r.name}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <button className="p-2.5 rounded-lg text-gray-500 hover:text-[#7c3aed]"><Heart className="w-5 h-5" /></button>
            <button className="relative p-2.5 rounded-lg text-gray-500 hover:text-[#7c3aed]">
              <ShoppingCart className="w-5 h-5" />
            </button>
            <button onClick={onLoginClick} className="hidden sm:flex items-center gap-2 px-4 py-2 bg-[#7c3aed] text-white rounded-lg font-medium"><User className="w-4 h-4" /><span>Entrar</span></button>
          </div>
        </div>
      </div>
    </header>
  )
}